"""
MKT Original Commentary — Job chapters 8–11
Run: python3 scripts/zc-original-job-8-11.py

Key linguistic notes:
- 8:3: 'awat (pervert/distort) — piel of the root for injustice
- 8:13-14: tikvah (hope) / 'akkabish (spider, hapax) — botanical/entomological analogies
- 9:2: yitsdaq (be declared righteous) — legal/forensic, not merely moral
- 9:8: dorek 'al-bamote yam (walks on the heights of the sea) — sea-walking motif
- 9:33: mokhiach (umpire/arbiter) — Job's longing for a mediator (1 Tim 2:5)
- 10:3: ma'aseh yadekha (work of your hands) — creature-dignity appeal
- 10:9-10: potter-clay; milk-and-cheese embryology — intimate creation language
- 10:12: hesed (steadfast love) — Job attributes covenant loyalty to God even in crisis
- 11:6: kiplayim le-tushiyyah (double in sound wisdom) — tushiyyah = abiding wisdom
- 11:12: wild donkey / human birth proverb — idiomatic "never"
- 11:20: mappah-naphesh (breathing out of the throat) — grim tikvah wordplay
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOB = {
  "8": {
    "1": "<p>Bildad the Shuhite is identified by region: Shuah was a son of Abraham by Keturah (Gen 25:2), placing him in the Aramean/North Arabian belt. The three Friends represent the wisdom traditions of the eastern peoples — Eliphaz (Teman/Edomite), Bildad (Shuhite/Aramean), Zophar (Naamathite/unknown Arabian) — all respectable carriers of international wisdom tradition. Their credentials are part of the narrative setup: these are not ignorant accusers but representatives of the best human wisdom available.</p>",
    "2": "<p><em>Kammāh timallēl-rûaḥ</em> — &#8220;how long will you speak wind?&#8221; The Hebrew <em>rûaḥ</em> (wind/spirit/breath) functions as a derogatory term for empty speech; Bildad is essentially calling Job&#8217;s lament hot air. The irony is that YHWH will speak from a storm/whirlwind (<em>sᵉʿārāh</em>) in chapter 38, and will condemn the Friends&#8217; words, not Job&#8217;s, as theologically incorrect (42:7).</p>",
    "3": "<p><em>Hăyᵉʿawwēl ʾēl mišpāṭ</em> — &#8220;does God pervert justice?&#8221; The piel of <em>ʿāwat</em> (pervert/distort) uses the same root as <em>ʿawlāh</em> (wickedness, injustice). Bildad&#8217;s theology is correct in the abstract: YHWH does not pervert justice. The MKT renders &#8220;distort&#8221; to capture the spatial metaphor — justice bent, curved away from the straight. The error is not in Bildad&#8217;s theology but in his application: he assumes the present situation is a straightforward case of justice in operation.</p>",
    "4": "<p><em>ʾim-ḥāṭᵉʾû ḇānêḵā lô wayyᵉšallᵉḥēm biḏê pišʿām</em> — &#8220;if your children sinned against him, he gave them over to the consequences of their own sin.&#8221; <em>Pišʿām</em> (their transgression) uses the same root as the legally weightiest word for deliberate rebellion; <em>šillaḥ</em> (gave them over) is the same word used for divine abandonment to consequences. Bildad is saying Job&#8217;s dead children got what their sins deserved — a brutal pastoral move against a grieving father, and one the narrative frame of chapters 1-2 has already refuted.</p>",
    "5": "<p><em>ʾim-ʾattāh tᵉšaḥēr ʾel-ʾēl</em> — &#8220;if you will seek God earnestly.&#8221; <em>Šāḥar</em> means &#8220;to seek/look for early in the morning&#8221; — the dawn-seeking intensity of diligent prayer; the same root appears in Psalm 63:1 (&#8220;early I will seek you&#8221;). <em>Ḥānan</em> (plead for grace) is the grace-vocabulary of the Psalter; Bildad instructs Job to do exactly what Job has been doing — pleading before God — but frames it as the condition Job has not yet met.</p>",
    "6": "<p><em>ʾim-zak wᵉyāšār ʾāttāh kî-ʿattāh yāʿîr ʿāleḵā</em> — &#8220;if you are pure and upright.&#8221; <em>Zak</em> (pure) and <em>yāšār</em> (upright) are the exact terms the narrator uses to describe Job in 1:1 (&#8220;blameless and upright&#8221; — <em>tām wᵉyāšār</em>); Bildad&#8217;s conditional uses Job&#8217;s own credentials as if they were yet to be established, while the reader knows they were established before the opening. The promise &#8220;he will restore your righteous home&#8221; will be fulfilled at the book&#8217;s end, but not because of Bildad&#8217;s advice.</p>",
    "7": "<p><em>wᵉhāyāh rēʾšîṯᵉḵā miṣʿār ûʾaḥărîṯᵉḵā yiśgeh mᵉʾōḏ</em> — &#8220;though your beginnings were humble, your latter years will be far greater.&#8221; The saying echoes the conventional wisdom of restoration after humble beginnings; the identical promise is quoted in Job 42:12 when God actually does restore Job. Bildad gets the outcome right while completely misreading the path.</p>",
    "8": "<p><em>šāʾal-nāʾ lᵉḏôr rišôn</em> — &#8220;ask the former generations.&#8221; The appeal to ancestral wisdom (<em>ḏôr rišôn</em> = first/former generation) is Bildad&#8217;s epistemological method: traditional wisdom accumulated across generations is the most reliable guide. This is contrasted with Job&#8217;s appeal to his own experience. The tension between inherited tradition and lived experience is one of the book&#8217;s structural concerns.</p>",
    "9": "<p><em>kî-ṯmôl ʾᵃnaḥnû wᵉlōʾ nēḏāʿ</em> — &#8220;for we are but of yesterday and know nothing.&#8221; The phrase <em>kî-ṯmôl</em> (for yesterday/as of yesterday) is an idiom for temporal insignificance; compare the same expression in 1 Chr 29:15 (&#8220;our days on earth are like a shadow&#8221;) and Ps 90:4 (a thousand years are like a watch in the night). Bildad&#8217;s epistemological humility about the present generation ironically applies more to himself than he realizes.</p>",
    "10": "<p><em>hălōʾ-hēmmāh yôrûḵā wᵉyōmrû lāḵ</em> — &#8220;will they not teach you, tell you, and speak?&#8221; The three verbs of instruction (<em>yārah</em> = teach/instruct; <em>ʾāmar</em> = tell; <em>ṣāʾ</em> = bring forth words) describe the full transmission process of traditional wisdom. <em>Yārah</em> is the same root as <em>tôrāh</em> (instruction/Torah), placing Bildad&#8217;s appeal to tradition in the same category as divine instruction.</p>",
    "11": "<p><em>hăyiśgeh-gōmeʾ bilōʾ biṣṣāh</em> — &#8220;can papyrus grow where there is no marsh?&#8221; <em>Gōmeʾ</em> (papyrus/bulrush) is an Egyptian loanword — the same plant Moses&#8217; basket was made of (Exod 2:3). The botanical analogy is precise: marsh plants require their specific habitat. The argument is analogical — just as these plants require their cause, suffering requires a cause (sin). The analogy is logically valid; the application to Job is not.</p>",
    "12": "<p><em>ʿōḏennû ḇᵉʾibbô lōʾ yiqqāṭēp wᵉlipnê ḵol-ḥāṣîr yiḇāš</em> — &#8220;though it is still green and not yet cut, it withers before any other herb.&#8221; The sudden collapse of the plant that seemed well-watered is the analogy for the apparent prosperity of the wicked; <em>yibbāš</em> (wither) is the same verb used in Ps 102:4 and Isa 40:7-8 (the grass withers). The reversal from green-and-lush to withered-before-anything-else captures the instability of prosperity without God.</p>",
    "13": "<p><em>kēn ʾorḥôṯ kol-šōkᵉḥê ʾēl wᵉtiqwaṯ ḥānēp tōʾḇēḏ</em> — &#8220;such is the end of all who forget God; the hope of the godless will come to nothing.&#8221; <em>Tiqwāh</em> (hope) is a key Job-term, appearing also in 14:19 (you wash away the hope of man) and 19:10 (my hope he has uprooted like a tree). Bildad claims confident knowledge of whose hope will fail; the book&#8217;s irony is that it is Bildad&#8217;s own theological hope (Job is guilty and will be exposed) that fails.</p>",
    "14": "<p><em>ʾᵃšer-yāqôṭ kiślô wᵉbêṯ ʿakkāḇîš miṭḥô</em> — &#8220;what he trusts in will be cut off, and his confidence is like a spider&#8217;s web.&#8221; <em>ʿAkkāḇîš</em> (spider) is a hapax legomenon — appearing only here in the OT; the image of spider-web fragility is striking precisely because the web appears intricate and strong while being wholly unable to bear weight. <em>Kiślô</em> (his confidence) shares a root with the constellation Kesil/Orion — both carry the sense of foolish overconfidence in something that will not hold.</p>",
    "15": "<p><em>yiššāʿēn ʿal-bêṯô wᵉlōʾ yaʿᵃmōḏ</em> — &#8220;he leans against his house, but it does not stand.&#8221; The image of leaning on something that gives way is the standard OT figure for misplaced trust (cf. Ezek 29:7 — leaning on Egypt as a broken reed). The house (<em>bêṯ</em>) that cannot support the one who clings to it is both literal and metaphorical: the worldly establishment that prosperity-religion builds will not hold when tested.</p>",
    "16": "<p><em>rāṭōb hûʾ lipnê-šāmeš ûʿal gannāṯô yanṭᵉriḥa yônaqtô</em> — &#8220;he is well-watered in the sunshine, his shoots spreading over the garden.&#8221; The image shifts from the spider&#8217;s web to a lush garden plant — the wicked man&#8217;s temporary prosperity is like rapid growth that looks impressive but is not rooted. The garden imagery inverts the Eden pattern: apparently flourishing, actually headed for destruction.</p>",
    "17": "<p><em>ʿal-gal šārāšāyw yᵉsûḇāḵû bêṯ ʾᵃḇānîm yehĕzeh</em> — &#8220;his roots twine around the pile of stones; he forces his way into a stony place.&#8221; The aggressive root-growth into inhospitable stone looks like resilience but is actually rootlessness in disguise: there is no genuine nourishment in stone. The image of invasive roots finding purchase in rock only to be suddenly uprooted (v.18) captures the sudden reversibility of ungodly prosperity.</p>",
    "18": "<p><em>ʾim-yᵉḇallᵉʿennû mimᵉqômô wᵉkiḥeš bô lōʾ rᵉʾîṯîḵā</em> — &#8220;but if he is destroyed from his place, it says to him: &#8216;I have never seen you.&#8217;&#8221; The impersonal &#8220;it says&#8221; refers to the place itself — the land the wicked man inhabited denies knowing him. This personification of place as witness echoes Abel&#8217;s blood crying from the ground (Gen 4:10); the earth itself testifies against the wicked.</p>",
    "19": "<p><em>hēn-hûʾ mᵉśôś darkô ûmeʿāpār ʾaḥēr yiṣmāḥû</em> — &#8220;behold, such is the joy of his path; and from the earth others will spring up in his place.&#8221; The sarcastic &#8220;such is the joy&#8221; (<em>mᵉśôś darkô</em>) announces the replacement of the wicked by others — the earth continues indifferently. Bildad&#8217;s point is that the pattern recycles: the godless flourish and fall, and others take their place; only the righteous escape this cycle.</p>",
    "20": "<p><em>hēn ʾēl lōʾ yimʾas tām</em> — &#8220;God does not reject the blameless.&#8221; <em>Tām</em> (blameless/complete) is the same word used of Job in 1:1 and 1:8; YHWH himself calls Job <em>tām</em>. Bildad&#8217;s assertion is true — God does not reject the blameless — and will be demonstrated by the book&#8217;s end. But Bildad&#8217;s implication (therefore Job is not blameless, since he is apparently rejected) is the error the narrative refutes.</p>",
    "21": "<p><em>ʿaḏ-yᵉmallēʾ śᵉḥôq pîḵā ûśpāṯeḵā tᵉrûʿāh</em> — &#8220;he will yet fill your mouth with laughter and your lips with joyful shouts.&#8221; <em>Śᵉḥôq</em> (laughter) is the word used for Sarah&#8217;s laughter (Gen 21:6) and for the laughter of restored Zion (Ps 126:2). Bildad&#8217;s promise of restored laughter is ironically accurate: in 42:10-17, Job&#8217;s latter days are greater; but the path there is through the whirlwind, not through Bildad&#8217;s prescribed repentance.</p>",
    "22": "<p><em>śōnᵉʾêḵā yilbᵉšû-ḇōšeṯ wᵉʾōhel rᵉšāʿîm ʾênennû</em> — &#8220;your enemies will be clothed with shame, and the tent of the wicked will vanish.&#8221; The reversal-of-garments motif — enemies wearing shame while the righteous wear joy (cf. Ps 109:29) — is standard covenant-theology language. The &#8220;tent of the wicked&#8221; that vanishes echoes 8:15&#8217;s house that cannot stand. Bildad ends with standard encouragement, theologically correct, pastorally catastrophic in its implicit accusation.</p>"
  },
  "9": {
    "1": "<p>Chapter 9 is Job&#8217;s response to Bildad and marks the escalation from theological discourse to legal metaphor: Job begins to frame his situation as a lawsuit (<em>rîḇ</em>) against God. The courtroom vocabulary that accumulates in ch 9 — justify, answer, argue, umpire, summon — is the most sustained legal imagery in the book outside the divine speeches.</p>",
    "2": "<p><em>ûmah-yiṣdaq ʾĕnôš ʿim-ʾēl</em> — &#8220;how can a man be justified before God?&#8221; <em>Yiṣdaq</em> is the niphal of <em>ṣādaq</em> (to be righteous/declared righteous) — a legal/forensic term, not merely a moral description. Job takes Bildad&#8217;s implicit question (8:3 — does God pervert justice?) and applies it existentially: even granting that God&#8217;s justice is real, how can any creature establish righteousness in a divine court? The question is not rhetorical despair but genuine legal inquiry.</p>",
    "3": "<p><em>ʾim-yāḥpoṣ lārîḇ ʿimmô lōʾ-yaʿᵃnennû ʾaḥaṯ mittî-ʾelep</em> — &#8220;one could not answer him once in a thousand attempts.&#8221; The legal odds — 1 in 1000 — are not pessimism but legal realism about the asymmetry between human and divine standards of proof. The same impossibility is used positively in Eccl 7:28 and Job 33:23 (if there is an angel to interpret, one among a thousand).</p>",
    "4": "<p><em>ḥᵃḵam lēḇāḇ wᵉʾammîṣ kōaḥ</em> — &#8220;God is wise in heart and mighty in strength.&#8221; The pairing of wisdom and power is the same pairing Job celebrates in 12:13 (&#8220;with God are wisdom and strength&#8221;) and that Paul applies to Christ (1 Cor 1:24). Job&#8217;s acknowledgment of divine wisdom-and-power is not defiance but context-setting: if even Rahab&#8217;s allies are subdued by this power (v.13), what chance does Job have in court?</p>",
    "5": "<p><em>hāmmַʿtîq hārîm wᵉlōʾ yāḏᵉʿû</em> — &#8220;he removes mountains before they know it.&#8221; The suddenness of divine action — mountains overturned in anger before they are aware — echoes the cosmological power descriptions that recur through the book. The image of mountains uprooted anticipates the whirlwind speech&#8217;s questions about cosmological foundations (38:4-6).</p>",
    "6": "<p><em>hammargîz ʾereṣ mimmᵉqômāh wᵉʿammûḏeḥā yiṯpallāṣûn</em> — &#8220;who shakes the earth from its place so that its pillars quake.&#8221; The <em>ʿammûḏîm</em> (pillars) of the earth are cosmological elements; the image of earth-pillars quaking connects to Ps 75:3 (I have set the pillars firm), Isa 24:18-20, and the theophany descriptions of divine judgment. Seismic disruption as divine action is a consistent OT theophanic motif.</p>",
    "7": "<p><em>hāʾōmēr laḥereš wᵉlōʾ yizrāḥ wᵉḇaʿᵃḏ kôḵāḇîm yaḥtōm</em> — &#8220;who commands the sun not to rise, and seals up the stars.&#8221; The command-form (<em>hāʾōmēr</em> — the one who says to) emphasizes divine speech-as-command over celestial mechanics; the sun&#8217;s non-rising and the stars&#8217; sealing (like a letter sealed with wax) represent the suspension of natural order. This is the counterpart to Gen 1:3 (&#8220;and God said... let there be light&#8221;) — the same God who issued the creative command can revoke it.</p>",
    "8": "<p><em>nōṭeh šāmayim lᵉḇaddô wᵉdōrēḵ ʿal-bāmŏṯê yām</em> — &#8220;who alone stretched out the heavens and walks on the crests of the sea.&#8221; <em>Dōrēḵ ʿal-bāmŏṯê yām</em> (walks/treads on the heights/back of the sea) is the earliest attested OT form of the divine sea-walking motif; cf. Hab 3:15; Ps 77:19. This is the conceptual precursor to Jesus walking on water (Matt 14:25-26; John 6:19), where the disciples&#8217; recognition — &#8220;truly you are the Son of God&#8221; — reflects the Joban theology that only God treads the sea.</p>",
    "9": "<p><em>ʿōśeh ʿāš kᵉsîl wᵉḵîmāh wᵉḥaḏrê ṯêmān</em> — &#8220;who made the Bear, Orion, and the Pleiades.&#8221; <em>ʿAš</em> (the Bear/Arcturus), <em>kᵉsîl</em> (Orion — from the root for foolishness; the fool-constellation), and <em>kîmāh</em> (Pleiades) are three of the book&#8217;s five astronomical references (also in 38:31-32). The Creator&#8217;s authorship of the constellations is the ground of YHWH&#8217;s own challenge in 38:31: &#8220;Can you bind the chains of the Pleiades?&#8221; — the same constellations Job cites here as evidence of divine power.</p>",
    "10": "<p><em>ʿōśeh gᵉḏōlôṯ ʿaḏ-ʾên ḥēqer wᵉniplāʾôṯ ʿaḏ-ʾên mispār</em> — &#8220;who does great things beyond comprehension and marvelous things without number.&#8221; This verse is nearly identical to 5:9 (Eliphaz&#8217;s doxology); Job is quoting Eliphaz&#8217;s own theological description of God and applying it as evidence that Job cannot win a divine lawsuit. The shared vocabulary (&#8220;unsearchable,&#8221; &#8220;without number&#8221;) shows Job mastering the Friends&#8217; own theological categories while reaching opposite practical conclusions.</p>",
    "11": "<p><em>hēn yaʿᵃḇōr ʿālay wᵉlōʾ ʾerʾeh wᵉyaḥᵃlōp wᵉlōʾ-ʾāḇîn lô</em> — &#8220;when he passes by me, I cannot see him; when he moves on, I cannot perceive him.&#8221; The invisibility of God in action — passing but unseen — is not atheism but a description of the divine <em>incognito</em>; cf. the divine presence passing before Moses (Exod 33:22) and Elijah (1 Kgs 19:11). The inability to perceive God passing is one of the existential crises of Job&#8217;s situation: God is active but not legible.</p>",
    "12": "<p><em>hēn yaḥtōp mî yᵉšîḇennû mî-yōmar ʾēlāyw māh-taaśeh</em> — &#8220;if he snatches something away, who can stop him? Who will dare say to him, &#8216;What are you doing?&#8217;&#8221; The question &#8220;what are you doing?&#8221; (<em>māh-taʿᵃśeh</em>) echoes the question that Job wishes he could ask; it also anticipates the ironic reversal in the whirlwind when God asks Job essentially the same question — &#8220;Where were you when I laid the foundation of the earth?&#8221; (38:4).</p>",
    "13": "<p><em>ʾĕlôhah lōʾ-yāšîḇ ʾappô taḥtāyw šāḥᵃḥû ʿōzᵉrê Rahaḇ</em> — &#8220;God does not restrain his anger; even the allies of Rahab crouched beneath him.&#8221; <em>Rahaḇ</em> here is the chaos-dragon of cosmogonic conflict (distinct from Rahab of Jericho), paralleling the Babylonian <em>Tiamat</em> and related to <em>tannîn</em> (dragon) in 3:8 and 26:12. The &#8220;allies of Rahab&#8221; — forces of primordial chaos — are subdued; if even cosmic chaos forces submit to God, Job has no legal recourse through power.</p>",
    "14": "<p><em>ʾap kî-ʾānōḵî ʾeʿᵃnennû ʾeḇḥᵃrāh ḏᵉḇāray ʿimmô</em> — &#8220;how then can I answer him, or select my words to argue before him?&#8221; <em>Eḇḥᵃrāh ḏᵉḇāray</em> (I will choose/select my words) describes the careful rhetorical preparation of a legal advocate; Job recognizes that even if he prepares his best case, the asymmetry of the courtroom makes victory impossible on his own terms. The careful word-selection of chapters 9-10 is itself the enacted form of this preparation.</p>",
    "15": "<p><em>ʾᵃšer ʾim-ṣāḏaqtî lōʾ ʾeʿᵃneh lᵉmišpāṭî ʾetḥannān</em> — &#8220;even if I were righteous, I could not answer him; I would have to plead for mercy to my own judge.&#8221; The legal paradox: even a righteous defendant must appeal to mercy rather than justice before this judge. <em>ʾetḥannān</em> (I would plead for grace/mercy) uses the same <em>ḥānan</em> root as Bildad&#8217;s advice in 8:5. Job discovers that the only possible stance before God is grace-seeking — but even this seems inadequate given God&#8217;s apparent disregard for Job&#8217;s cries.</p>",
    "16": "<p><em>ʾim-qārāʾṯî wayyaʿᵃnēnî lōʾ-ʾaʾᵃmîn kî-yaʾᵃzîn qôlî</em> — &#8220;if I summoned him and he responded, I still could not believe he was truly listening to me.&#8221; The crisis of divine responsiveness: even a divine answer would not resolve Job&#8217;s epistemic problem, because he cannot verify that God is genuinely attending to his case. This anticipates the whirlwind response — God does answer Job, and Job&#8217;s response (40:4-5; 42:1-6) is the unexpected form of &#8220;believing God is listening.&#8221;</p>",
    "17": "<p><em>ʾᵃšer bisᵉʿārāh yᵉšûpᵉnî wᵉhirᵉbāh pᵉṣāʿay ḥinnām</em> — &#8220;for he would crush me with a storm and multiply my wounds for no reason.&#8221; <em>Bisᵉʿārāh</em> (with a storm/whirlwind) uses the exact same root as the <em>sᵉʿārāh</em> from which YHWH actually speaks in 38:1 — &#8220;out of the storm the LORD answered.&#8221; Job anticipates the divine answer will be crushing force; YHWH&#8217;s actual whirlwind-speech is confrontational but not obliterating — it is the answer that restores Job (42:5-6).</p>",
    "18": "<p><em>lōʾ-yitᵉnnênî hāšēḇ rûḥî kî yaśbîʿanî mamrōrîm</em> — &#8220;he does not let me catch my breath, but fills me with bitter suffering.&#8221; <em>Hāšēḇ rûḥî</em> (restore my breath/spirit) is the language of near-death recovery; Job is at the edge of being overwhelmed. <em>Mamrōrîm</em> (bitter things) shares a root with Naomi&#8217;s name-change request (<em>Mārā</em> = bitter; Ruth 1:20) — the vocabulary of suffering that has turned life to bitterness.</p>",
    "19": "<p><em>ʾim-lᵉkōaḥ ʾammiṣ hinnēh wᵉʾim-lᵉmišpāṭ mî yôʿîḏēnî</em> — &#8220;if it is a contest of strength, he is the stronger; if it is a matter of justice, who can summon him to court?&#8221; The double impossibility: strength argument fails (God has more); justice argument fails (God cannot be summoned). The only remaining resource is the mediator/umpire Job will request in v.33.</p>",
    "20": "<p><em>ʾim-ʾeṣdaq pî yaršîʿēnî tām-ʾānî wayᵉʿaqqᵉšēnî</em> — &#8220;if I justified myself, my own mouth would condemn me; if I declared myself blameless, he would prove me crooked.&#8221; The legal trap: self-justification generates self-condemnation because the standard being applied exceeds what any creature meets. The same logic drives Paul in Rom 3:19-20 (the law silences every mouth and makes all the world accountable to God).</p>",
    "21": "<p><em>tām ʾānî lōʾ-ʾēḏaʿ napšî ʾemʾas ḥayyāy</em> — &#8220;though I am blameless, I do not trust my own self-knowledge; I despise my own life.&#8221; <em>Tām ʾānî</em> (I am blameless) reaffirms Job&#8217;s integrity even as he disclaims confident self-knowledge. The epistemological humility — not knowing his own soul fully — is one of Job&#8217;s most honest moments; he is not asserting perfect self-transparency but genuine integrity based on available evidence. This anticipates Paul&#8217;s similar statement in 1 Cor 4:3-4.</p>",
    "22": "<p><em>ʾaḥaṯ hîʾ ʿal-kēn ʾāmartî tām wᵉrāšāʿ hûʾ mᵉkalleh</em> — &#8220;it is all the same to me; this is why I say: he destroys the blameless and the wicked alike.&#8221; Job&#8217;s most radical claim — that divine retributive distinction is empirically absent. This is not atheism but crisis-theodicy: Job is not denying God&#8217;s existence but questioning the operational reliability of the retributive principle. The book will eventually validate Job&#8217;s integrity while not vindicating this particular claim.</p>",
    "23": "<p><em>ʾim-šôṭ yāmîṯ pitʾōm limsaṯ nᵉqiyyîm yilʿāḡ</em> — &#8220;when sudden disaster brings death, he mocks at the calamity of the innocent.&#8221; <em>Yilʿāḡ</em> (mocks/laughs) applied to God is Job&#8217;s most provocative statement — yet cf. Ps 2:4 (God laughs at human schemes) and Prov 1:26 (Wisdom laughs at the calamity of those who rejected her). Job&#8217;s accusation is extreme but uses vocabulary the tradition applied to God in other contexts.</p>",
    "24": "<p><em>ʾereṣ nitᵉnāh bᵉyaḏ-rāšāʿ pᵉnê-šōpᵉṭeḥā yᵉkasseh ʾim-lōʾ ʾēpôʾ mî-hûʾ</em> — &#8220;the earth is given into the power of the wicked; he blindfolds its judges. If not he, then who?&#8221; The rhetorical question &#8220;if not he, then who?&#8221; (<em>ʾim-lōʾ ʾēpôʾ mî-hûʾ</em>) is Job&#8217;s form of theodicy-demand: if God is sovereign, God is responsible for the observable injustice; if God is not responsible, then who? The Friends have no answer to this question; the whirlwind does not give a direct answer either — it reframes the question.</p>",
    "25": "<p><em>wᵉyāmay qallû minnî-rāṣ</em> — &#8220;my days are swifter than a runner.&#8221; The speed-of-life metaphors multiply: runner, reed skiffs, diving eagle — each faster than the last. The accumulation of velocity images captures the experience of time accelerating in suffering; there is no time to establish the righteousness Job claims before his life ends.</p>",
    "26": "<p><em>ḥālᵉpû ʿim-ʾonîyyôṯ ʾēḇeh kᵉneser yāṭûš ʿᵃlê-ʾōkel</em> — &#8220;they glide away like skiffs of reed, like an eagle diving on its prey.&#8221; <em>ʾOnîyyôṯ ʾēḇeh</em> (boats/skiffs of papyrus/reed) — light Egyptian papyrus vessels known for speed on the Nile; the eagle diving (<em>yāṭûš</em>) on prey is the same eagle of 39:29-30; Job&#8217;s life is as fleeting as the fastest things he knows.</p>",
    "27": "<p><em>ʾim-ʾāmartî ʾeškaḥāh śîḥî ʾeʿezbāh pānay wᵉʾabliḡāh</em> — &#8220;if I say, &#8216;I will forget my complaint, I will put on a cheerful face and be bright.&#8217;&#8221; Job considers the option of forced optimism — the social performance of well-being — and immediately rejects it (v.28): he knows it is impossible because the underlying dread remains. The authentic lament tradition refuses cosmetic cheerfulness as a response to genuine suffering.</p>",
    "28": "<p><em>yāgōrtî kol-ʿōṣᵉḇōṯay yāḏaʿtî kî-lōʾ tᵉnaqqēnî</em> — &#8220;I dread all my suffering, for I know you will not acquit me.&#8221; <em>Tᵉnaqqēnî</em> (acquit/declare innocent) is the legal term from <em>nāqāh</em> (to be clean/innocent); Job&#8217;s certainty of divine non-acquittal is a crisis of faith, not an absence of faith. The certainty that God will not declare him innocent despite his being innocent is the book&#8217;s central paradox until the whirlwind resolves it by declaring Job&#8217;s words &#8220;right&#8221; (42:7).</p>",
    "29": "<p><em>ʾānōḵî ʾerāšaʿ lāmmāh-zeh heḇel ʾiyygāʿ</em> — &#8220;if I am condemned already, why do I exhaust myself for nothing?&#8221; <em>Heḇel</em> (vapor/breath/futility) — the same word that dominates Ecclesiastes — here applies to Job&#8217;s legal effort: if the outcome is predetermined, the effort is <em>heḇel</em>. The word&#8217;s Ecclesiastes usage asks the same theodicy question from a different angle.</p>",
    "30": "<p><em>ʾim-hiṯrāḥaṣtî ḇᵉmê-šāleg</em> — &#8220;even if I washed myself with snow water.&#8221; Snow water (<em>mê šāleg</em>) was regarded as the purest available water; the conditional sets up the maximal purity scenario. The futility of even maximum purity before God parallels Isa 64:6 (&#8220;all our righteous acts are like filthy rags&#8221;) — though Job&#8217;s lament is about innocence-while-condemned, not about the insufficiency of righteousness per se.</p>",
    "31": "<p><em>ʾāz baššaḥaṯ tiṭbᵉlēnî wᵉtiʿᵃḇûnî śalmôṯay</em> — &#8220;you would still plunge me into a slime pit so that my own clothes would recoil from me.&#8221; <em>Šaḥaṯ</em> (pit/grave/corruption) — the same word used in Ps 16:10 (&#8220;you will not abandon me to the realm of the dead, nor will you let your faithful one see decay&#8221;) and Jon 2:6. The clothes recoiling from the defiled wearer — even Job&#8217;s garments reject him — captures extreme defilement imagery.</p>",
    "32": "<p><em>kî lōʾ-ʾîš kāmônî ʾeʿᵃnennû nāḇôʾ yaḥḏāw bammišpāṭ</em> — &#8220;for he is not a man as I am, that I could answer him or that we could appear in court together.&#8221; <em>Lōʾ-ʾîš kāmônî</em> (not a man like me) is one of Job&#8217;s most theologically loaded statements. The asymmetry Job laments — God is not human, therefore the legal process is inaccessible — is the precise condition that the incarnation addresses: &#8220;the Word became flesh&#8221; (John 1:14) makes the divine party to the case human and therefore subject to the legal encounter Job cannot achieve.</p>",
    "33": "<p><em>lōʾ-yēš bênênû môkîaḥ yāšêṯ yāḏô ʿal-šᵉnênû</em> — &#8220;there is no umpire between us who could place his hand upon us both.&#8221; <em>Môkîaḥ</em> (umpire/arbiter/one who argues/decides) is from the root <em>yākaḥ</em> (to argue, reprove, decide a case); the same root produces the prophetic <em>hôkîaḥ</em> (to rebuke/decide). The umpire who can lay hands on both God and human is the central longing of the book — and its NT answer is explicit: &#8220;For there is one God and one mediator between God and mankind, the man Christ Jesus&#8221; (1 Tim 2:5). Job&#8217;s umpire-longing is one of the OT&#8217;s clearest anticipations of the incarnate mediator.</p>",
    "34": "<p><em>yāsēr mēʿālay šiḇṭô wᵉʾêmāṯô ʾal-tᵉḇaʿᵃtanî</em> — &#8220;let him remove his rod from me, and let his terror not overwhelm me.&#8221; The <em>šēḇeṭ</em> (rod/staff) here is the instrument of divine discipline/punishment, not of comfort as in Ps 23:4. Job is asking for the removal of both the punishment and the terror — what he wants is a hearing without the judicial pressure that makes honest speech impossible. He will eventually get this at the whirlwind: God speaks, but from 38:3 onward it is God who does the cross-examining.</p>",
    "35": "<p><em>ʾᵃḏabbēr wᵉlōʾ ʾîrāʾennû kî lōʾ-ḵēn ʾānōḵî ʿimmāḏî</em> — &#8220;then I would speak without fear, for I am not so in myself.&#8221; Job&#8217;s condition for honest speech is removal of the terror that suppresses his words; the whirlwind encounter actually fulfills this when God commands Job: &#8220;brace yourself like a warrior; I will question you, and you will answer me&#8221; (38:3; 40:7). The invitation to answer without annihilation is the version of Job&#8217;s request that YHWH grants.</p>"
  },
  "10": {
    "1": "<p><em>nāqᵉṭāh napšî bᵉḥayyāy ʾeʿezbāh ʿālāyw śîḥî ʾᵃḏabbēr bᵉmar napšî</em> — &#8220;my soul is sick of my life; I will give free rein to my complaint; I will speak in the bitterness of my soul.&#8221; <em>Nāqᵉṭāh napšî</em> (my soul loathes/is sick) — the verb <em>qûṭ</em> carries the sense of being cut off or disgusted; cf. Gen 27:46 (Rebekah&#8217;s loathing of life over Esau&#8217;s wives). <em>ʾeʿezbāh ʿālāyw śîḥî</em> — &#8220;I will release/let go my complaint upon him&#8221; — the idiom of dropping one&#8217;s restraint; Job&#8217;s address to God becomes direct from this verse forward.</p>",
    "2": "<p><em>ʾomar ʾel-ʾĕlôhah ʾal-taršîʿēnî hôḏîʿēnî ʿal-māh tᵉrîḇēnî</em> — &#8220;Do not condemn me; let me know why you bring charges against me.&#8221; <em>Taršîʿēnî</em> (condemn/declare wicked) is the legal opposite of <em>ṣādaq</em> (declare righteous); Job requests both an acquittal and an explanation. The request for an explanation — &#8220;let me know why&#8221; — is the central question of the book, and the whirlwind speech conspicuously does not answer it directly.</p>",
    "3": "<p><em>hăṭôḇ lᵉḵā kî-taʿᵃšōq kî-timʾas yᵉgîaʿ kappêḵā</em> — &#8220;does it please you to oppress, to reject the work of your own hands?&#8221; <em>Yᵉgîaʿ kappêḵā</em> (the work of your hands/the labor of your palms) appeals to the creator&#8217;s investment in the creature; the same phrase appears in Ps 128:2 (you shall eat the fruit of the labor of your hands) and 138:8 (do not abandon the work of your hands). The theological force: God has a stake in what God made; destruction of the creature undermines divine creative purpose.</p>",
    "4": "<p><em>hăʿênê ḇāśār lāḵ ʾim-kirʾôṯ ʾĕnôš tirʾeh</em> — &#8220;do you have eyes of flesh? Do you see as a human being sees?&#8221; The question is anthropological: divine perception versus human perception. The <em>ʿênê ḇāśār</em> (eyes of flesh) are eyes that are limited, temporal, fallible; YHWH&#8217;s eyes are not — yet Job is asking whether God is operating as if he has these limitations, judging by surface appearances like a human being. This is the problem that Job&#8217;s friends have: they see exactly as human beings see, drawing human inferences.</p>",
    "5": "<p><em>hǎkîmê ʾĕnôš yāmeḵā ʾim-šᵉnôṯeḵā kimê gāḇer</em> — &#8220;are your days like those of a human being, or your years like a man&#8217;s years?&#8221; The time-limitation question: if God&#8217;s days were finite, the urgency to condemn Job before evidence emerges would make sense. But God is eternal — there is no rush; no expiry date on investigation. The argument is that divine eternity should enable divine patience, which the present situation appears to contradict.</p>",
    "6": "<p><em>kî-ṯᵉḇaqqēš laʿᵃwōnî ûlᵉḥaṭṭāʾṯî ṯiḏrôš</em> — &#8220;that you search out my wrongdoing and inquire into my sin.&#8221; <em>Ṯᵉḇaqqēš</em> (search for/seek) and <em>ṯiḏrôš</em> (inquire into/seek out) together describe intensive forensic investigation. The irony Job notes: God is applying diligent prosecutorial resources to find Job&#8217;s guilt, but God knows (v.7) there is no guilt to find.</p>",
    "7": "<p><em>ʿal-daʿtᵉḵā kî-lōʾ ʾerāšaʿ wᵉʾên miyyāḏᵉḵā maṣṣîl</em> — &#8220;though you know I am not guilty, and no one can rescue me from your power.&#8221; The theological crux: God&#8217;s omniscience includes knowledge of Job&#8217;s innocence, yet the treatment continues. The omniscience-and-suffering tension is not resolved by Job but is implicitly resolved in 42:7-8 when God validates Job&#8217;s case retroactively.</p>",
    "8": "<p><em>yāḏeḵā ʿiṣᵉḇûnî wayyaʿᵃśûnî yaḥaḏ sāḇîḇ wattᵉḇallᵉʿēnî</em> — &#8220;your hands shaped and formed me — the whole of me — and now you turn and destroy me.&#8221; Two verbs of craftsmanship: <em>ʿāṣaḇ</em> (fashion/form/shape — used of potters, sculptors, image-makers) and <em>ʿāśāh</em> (make/do — the general creation verb of Gen 1); together they emphasize deliberate, skilled construction. <em>Yaḥaḏ sāḇîḇ</em> (altogether/all around) — God shaped every aspect of Job. The contrast with &#8220;swallow/destroy&#8221; (<em>bālaʿ</em>) is stark: the same hands that made now apparently consume.</p>",
    "9": "<p><em>zᵉḵār-nāʾ kî-kaḥōmer ʿāśîṯānî wᵉʾel-ʿāpār tᵉšîḇēnî</em> — &#8220;remember that you formed me like clay; will you now bring me back to dust?&#8221; <em>Kaḥōmer</em> (like clay) — the potter-clay metaphor of Gen 2:7 (formed from the dust of the ground) and Isa 64:8 (we are the clay, you are the potter). The appeal to clay-formation is simultaneously an argument for divine responsibility and for divine tenderness: clay is fragile; the potter should remember what the clay is made of.</p>",
    "10": "<p><em>hălōʾ kaḥālāḇ tattiḵēnî waggᵉḇînāh taqpîʾēnî</em> — &#8220;did you not pour me out like milk and curdle me like cheese?&#8221; The embryological analogy — liquid becoming solid, shapeless becoming shaped — is the OT&#8217;s most specific description of fetal development; cf. Ps 139:13-15 (woven in the womb). Ancient physiology understood conception as a process of coagulation of vital fluids; the poet uses this to describe the deliberateness and intimacy of divine creative involvement in human formation.</p>",
    "11": "<p><em>ʿôr wāḇāśār talḇîšēnî ûḇaʿᵃṣāmôṯ wᵉḡîḏîm tᵉśōḵᵉḵēnî</em> — &#8220;you clothed me with skin and flesh, and knit me together with bones and sinews.&#8221; <em>Tᵉśōḵᵉḵēnî</em> (knit/weave together) — the weaving metaphor for skeletal formation connects to Ps 139:13 (<em>tᵉsukkanî</em> — you wove/knitted me). The body described as a garment put on (<em>talḇîšēnî</em> — clothed me) positions the physical form as given by God, not inherent to the self — a garment that can be removed but was given by the same hands now apparently destroying it.</p>",
    "12": "<p><em>ḥayyîm wāḥeseḏ ʿāśîṯā ʿimmāḏî ûpᵉquddāṯᵉḵā šāmᵉrāh rûḥî</em> — &#8220;you gave me life and steadfast love (<em>ḥeseḏ</em>), and your watchful care preserved my spirit.&#8221; The attribution of <em>ḥeseḏ</em> (covenant steadfast love/loyalty) to God&#8217;s past action is theologically central: Job is not denying that God has shown covenant faithfulness — he is in crisis because the present experience contradicts the past. The tension between remembered <em>ḥeseḏ</em> and present silence is the spiritual anatomy of the book&#8217;s lament.</p>",
    "13": "<p><em>wᵉʾēlleh ṣāpantā ḇilḇāḇeḵā yāḏaʿtî kî-zōʾṯ ʿimmāḵ</em> — &#8220;yet these things you hid in your heart; I know that this was your purpose all along.&#8221; <em>Ṣāpantā ḇilḇāḇeḵā</em> (you hid in your heart) — Job suggests that the suffering was a predetermined divine intention, not an improvised punishment. The &#8220;purpose all along&#8221; reading gives Job&#8217;s theology a hidden-plan quality — divine concealment of intent that the reader knows was the testing of chapters 1-2.</p>",
    "14": "<p><em>ʾim-ḥāṭāʾṯî wᵉšāmartanî wᵉmeʿᵃwônî lōʾ ṯᵉnaqqēnî</em> — &#8220;if I sin, you take note of it and will not let my guilt go.&#8221; The relentless divine observation of sin (<em>šāmar</em> — keep watch) is experienced by Job as prosecutorial surveillance rather than protective care; the same word is used for protective keeping in Ps 121:4 (&#8220;he who keeps Israel will neither slumber nor sleep&#8221;). Divine watchfulness that ought to be comforting has become threatening in Job&#8217;s experience.</p>",
    "15": "<p><em>ʾim-rāšaʿtî ʾallay lî wᵉṣāḏaqtî lōʾ-ʾeśśāʾ rōʾšî</em> — &#8220;if I am wicked, woe to me! And if I am righteous, I still cannot hold my head up.&#8221; The double bind: the wicked are condemned; but the righteous cannot raise their heads either, because of the present humiliation. <em>ʾAllay lî</em> (woe to me!) is a self-directed curse expressing utter misery. The logical structure — wicked: condemned; righteous: still condemned — is the impossible situation Job is in.</p>",
    "16": "<p><em>wᵉyiśgeh kaššaḥal tᵉṣûḏēnî</em> — &#8220;but if I do hold my head up, you hunt me like a fierce lion.&#8221; <em>Šaḥal</em> (fierce lion) is used in Ps 91:13 for the lion the protected person treads upon; here it describes God as hunter. The inversion of the divine hunter-and-helper imagery is part of Job&#8217;s theodicy vocabulary — God as adversary rather than ally, using the strongest possible animal metaphors for power.</p>",
    "17": "<p><em>tᵉḥaddeš ʿēḏeḵā nᵉḡḏî</em> — &#8220;you bring fresh witnesses against me.&#8221; <em>ʿēḏeḵā</em> (your witnesses) — God as the one who produces witnesses for the prosecution rather than defending the accused. The Hebrew legal system required multiple witnesses for conviction (Deut 17:6); the image of God as the one continuously producing fresh witness-evidence against Job is the legal metaphor for the continuous suffering Job experiences.</p>",
    "18": "<p><em>wᵉlāmmāh mērāḥem hôṣēʾṯānî mibbeṭen</em> — &#8220;why then did you bring me out of the womb?&#8221; The birth-curse and wish-never-to-have-been pattern echoes Job&#8217;s opening speech in chapter 3 and connects to Jeremiah&#8217;s lament (Jer 20:14-18). The question &#8220;why bring me out of the womb?&#8221; is not suicidal but theodical — if this is what divine care looks like, the initial act of bringing to life appears to have been cruelty rather than kindness.</p>",
    "19": "<p><em>kaʾᵃšer lōʾ-hāyîṯî ʾihyeh mibbeṭen laqqeḇer ʾûḇāl</em> — &#8220;I should never have existed; I should have been carried straight from the womb to the grave.&#8221; The theological coherence of womb-to-grave without intermediate life — bypassing the suffering — is the impossible wish that echoes Ecclesiastes&#8217;s stillborn as better off than the living (Eccl 6:3-5). The OT allows lament to reach these extremes; Job&#8217;s hyperbole is authentic suffering speech, not theological confession.</p>",
    "20": "<p><em>hălōʾ-miʿaṭ yāmay yāḥᵃḏāl wᵉšîṯ mimmennî wᵉʾaḇliḡāh mᵉʿāṭ</em> — &#8220;are my days not few? Cease — leave me alone, that I may have a little relief before I go.&#8221; <em>ʾAḇliḡāh mᵉʿāṭ</em> (a little brightness/relief) — the verb <em>bālag</em> means to shine/gleam; the request for a brief brightening before death is the minimum request, not a demand for restoration. The <em>mᵉʿāṭ</em> (a little) acknowledges the terminal expectation.</p>",
    "21": "<p><em>bᵉṭerem ʾēlēḵ wᵉlōʾ ʾāšûḇ ʾel-ʾereṣ ḥōšeḵ wᵉṣalmāweṯ</em> — &#8220;to the land of darkness and the shadow of death, from which there is no return.&#8221; <em>Ṣalmāweṯ</em> (shadow of death) — a compound of <em>ṣēl</em> (shadow) and <em>māweṯ</em> (death); used in Ps 23:4 (&#8220;though I walk through the valley of the shadow of death&#8221;), Ps 107:10, and Isa 9:2 (&#8220;the people walking in darkness have seen a great light; on those living in the land of the shadow of death a light has dawned&#8221;). The darkness that Job anticipates entering is the darkness from which Isaiah promises a great light emerges.</p>",
    "22": "<p><em>ʾereṣ ʿêpāṯāh kaʾᵃpēlāh ṣalmāweṯ wᵉlōʾ sᵉḏārîm wattōpiaʿ kaʾōpel</em> — &#8220;a land of utter gloom like thick darkness, of the shadow of death and disorder, where even the light is like darkness.&#8221; The description of Sheol as a place of disorder (<em>lōʾ sᵉḏārîm</em> — without order/arrangements) and inverted light (light there is like darkness) echoes the pre-creation chaos of Gen 1:2 (formless and void, darkness over the deep). Job&#8217;s Sheol is a return to uncreation — the undoing of the cosmic order God established.</p>"
  },
  "11": {
    "1": "<p>Zophar the Naamathite is the least developed of the three Friends biographically; Naamah may be in northwestern Arabia (cf. Josh 15:41) or is unidentified. His is the shortest first speech (20 verses) and the shortest second speech (20:29); he alone has no third speech in the Masoretic text. His style is the most blunt and accusatory of the three.</p>",
    "2": "<p><em>hărōḇ dᵉḇārîm lōʾ yēʿāneh wᵉʾîm-śᵉpāṯayim yiṣdaq</em> — &#8220;should this flood of words go unanswered? Should a man of endless talk be counted righteous?&#8221; <em>Rōḇ dᵉḇārîm</em> (multitude of words) — the critique of verbosity as a moral indicator; cf. Eccl 5:2-3 (let your words be few; many words come with dreams and folly). The sarcasm is that quantity of speech is being conflated with quality of argument: Zophar dismisses Job&#8217;s words by volume, not content.</p>",
    "3": "<p><em>baddêḵā mᵉtîm yaḥᵃrîšû wattilaʿ wᵉʾên maklîm</em> — &#8220;shall your boasting silence everyone? When you scoff, will no one rebuke you?&#8221; <em>Baddêḵā</em> (your boastings/empty claims) — the plural of <em>baḏ</em> (linen/empty boast) — the Friends are silenced not because they lack arguments but because Job&#8217;s lament has overpowered their formulaic responses. Zophar frames this as a deficit: someone should be speaking back against Job&#8217;s scoffing.</p>",
    "4": "<p><em>kî tōmar zak leqqāḥî wᵉḇar hāyîṯî bᵉʿêneḵā</em> — &#8220;for you have said, &#8216;My doctrine is right and I am clean in God&#8217;s sight.&#8217;&#8221; <em>Leqqāḥî</em> (my doctrine/reception) — from <em>lāqaḥ</em> (to take/receive); the word implies received teaching, traditional doctrine accepted and carried. Zophar puts in Job&#8217;s mouth a doctrinal claim Job has not made in these terms; Job has claimed innocence of behavior, not doctrinal infallibility. This misrepresentation is part of the Friends&#8217; pattern.</p>",
    "5": "<p><em>wᵉʾûlam mî-yittēn ʾĕlôhah dabbēr wᵉyipṯaḥ śᵉpāṯāyw ʿimmāḵ</em> — &#8220;if only God would speak and open his lips to answer you.&#8221; The irony is enormous: Zophar wishes God would speak, apparently confident that God would vindicate his (Zophar&#8217;s) position; God will speak (chapters 38-41), but in vindication of Job, not of Zophar. The Friends&#8217; call for divine intervention backfires.</p>",
    "6": "<p><em>wᵉyaggēḏ lᵉḵā taʿᵃlumôṯ ḥokmāh kî-kiplayim lᵉṯûšiyyāh</em> — &#8220;and reveal to you the secrets of wisdom — for wisdom has more facets than you know.&#8221; <em>Kiplayim lᵉṯûšiyyāh</em> (double in sound wisdom) — <em>kiplāyim</em> (twofold/double) and <em>tûšiyyāh</em> (sound wisdom/abiding success/efficacy). <em>Tûšiyyāh</em> is a wisdom-technical term (Prov 2:7; 3:21; 8:14; Job 5:12; 12:16; 26:3) suggesting practical effectiveness that accomplishes its purpose. Zophar is saying: God has twice as much wisdom as you can see — implying Job&#8217;s suffering reveals a double portion of hidden divine wisdom-in-judgment that Job cannot access.</p>",
    "7": "<p><em>hăḥēqer ʾĕlôhah timṣāʾ ʾim ʾad-takkîṯ šadday timṣāʾ</em> — &#8220;can you search out the deep things of God? Can you find the limit of the Almighty?&#8221; <em>Ḥēqer</em> (searching, limit) — &#8220;unsearchable&#8221; in the NT (<em>anexeraunētos</em>, Rom 11:33) — Zophar uses the vocabulary of divine incomprehensibility correctly but with the wrong pastoral application: the unsearchability of God should produce humility in the sufferer, not accusations of the sufferer&#8217;s guilt.</p>",
    "8": "<p><em>gāḇhê šāmayim māh-tipʿāl ʿᵃmuqqāh mišᵉʾôl māh-tēḏāʿ</em> — &#8220;it is higher than the heavens — what can you do? Deeper than Sheol — what can you know?&#8221; The fourfold spatial description — higher than heaven, deeper than Sheol, longer than earth, broader than sea — is a cosmological mapping of divine incomprehensibility using all four dimensions: vertical up/down and horizontal. The quadrant imagery echoes Isa 40:12 (measuring the waters in the hollow of the hand).</p>",
    "9": "<p><em>ʾᵃrukāh mēʾereṣ midāḥ ûrᵉḥāḇāh min-yām</em> — &#8220;its measure is longer than the earth and broader than the sea.&#8221; The horizontal dimensions complete the cosmic mapping. The accumulation of spatial impossibilities — God&#8217;s wisdom exceeds every human framework — is the same argument the whirlwind speech makes, but where Zophar uses it as accusation (you can&#8217;t know, therefore submit to punishment), YHWH uses it as invitation to awe and trust.</p>",
    "10": "<p><em>ʾim-yᵉḥᵃlōp wᵉyaśgîr wᵉyaqhîl mî yᵉšîḇennû</em> — &#8220;if he sweeps through, imprisons, and convenes a court — who can stop him?&#8221; Three swift verbs of divine judicial action: <em>yᵉḥᵃlōp</em> (sweep through/pass by — same root as &#8220;pass by&#8221; in 9:11), <em>yaśgîr</em> (shut in/imprison), <em>yaqhîl</em> (convene an assembly/court). The swift judicial process allows no appeal; the rhetorical force parallels what Job said in 9:12 (&#8220;if he snatches away, who can stop him?&#8221;). Zophar and Job are using the same divine power-descriptions, but with different theological conclusions.</p>",
    "11": "<p><em>kî-hûʾ yēḏaʿ mᵉṯê-šāwᵉ</em> — &#8220;for he knows worthless people.&#8221; <em>Mᵉṯê-šāwᵉ</em> (men of vanity/worthlessness) — <em>šāwʾ</em> carries the sense of deception, emptiness, falsehood; used in the third commandment (&#8220;do not take the name of the LORD in vain&#8221; — <em>laššāwʾ</em>). Zophar is effectively classifying Job in this category without saying it directly — the whole speech is an extended accusation with the final term withheld.</p>",
    "12": "<p><em>wᵉʾîš nāḇôḇ yillāḇēḇ wᵉʿayir pereʾ ʾāḏām yiwwālēḏ</em> — &#8220;a hollow-headed man will become wise when a wild donkey gives birth to a human being.&#8221; <em>Nāḇôḇ</em> (hollow/empty) — the word for an empty vessel or reed; the hollow man becoming wise when a wild donkey gives birth to a human is an extreme adynaton (impossibility idiom) — the structural equivalent of &#8220;when pigs fly.&#8221; Zophar is saying Job&#8217;s becoming wise is as likely as this natural impossibility.</p>",
    "13": "<p><em>ʾim-ʾattāh hᵉḵînôṯā libbᵉḵā ûpāraśtā ʾēlāyw kappêḵā</em> — &#8220;if you would prepare your heart and stretch out your hands toward him.&#8221; <em>Hᵉḵînôṯā libbᵉḵā</em> (prepare/establish your heart) — <em>kûn</em> in the hiphil means to make firm, establish, fix rightly; cf. Ps 78:8 (their hearts not established/firm with God) and 1 Sam 7:3 (prepare your hearts for the LORD). The stretching of hands (<em>pāraś kappayim</em>) is the gesture of prayer; Zophar&#8217;s conditional instruction is genuinely pious — but applied to an innocent man.</p>",
    "14": "<p><em>ʾim-ʾāwen bᵉyāḏᵉḵā harḥîqēhû wᵉʾal-tašken bᵉʾohāleḵā ʿawlāh</em> — &#8220;if there is sin in your hand, remove it far away, and let wickedness have no place in your home.&#8221; <em>Harḥîqēhû</em> (remove it far) — the same idiom appears in Ps 103:12 (as far as the east is from the west, so far has he removed our transgressions). Zophar&#8217;s advice is theologically correct but morally catastrophic: Job&#8217;s home has already been destroyed, his children dead; commanding him to remove wickedness from his household is a second wound.</p>",
    "15": "<p><em>kî-ʾāz tissāʾ pāneḵā mimmûm wᵉhāyîṯā môṣāq wᵉlōʾ ṯîrāʾ</em> — &#8220;then surely you will lift up your face without shame; you will stand firm and have no fear.&#8221; The promise of restored dignity (lifting the face without shame) echoes the promise of 22:26 (Eliphaz) and the actual restoration in 42:8-10. The conditional &#8220;if you repent&#8221; will be fulfilled — but not because of Zophar&#8217;s diagnosis; it will be fulfilled because YHWH restores Job after the whirlwind, not after Zophar&#8217;s prescribed repentance.</p>",
    "16": "<p><em>kî-ʾattāh ʿāmāl tiškaḥ kᵉmayim ʿāḇrû tizkōr</em> — &#8220;for you will forget your suffering; you will remember it only as water that has long since flowed on.&#8221; The water-memory image — suffering as rivers that pass and leave no trace — is a comforting image of selective forgetting; cf. Isa 65:16 (the former troubles will be forgotten). The promise of future forgetfulness will be partially fulfilled: 42:10-17 shows restoration, though the deaths of Job&#8217;s first children are never unfelt.</p>",
    "17": "<p><em>ûmissohᵃrayim yāqûm ḥeled ṯᵉʿupāh kaḇōqer yihyeh</em> — &#8220;your life will shine brighter than noon; even your darkest time will be like dawn.&#8221; Light/darkness reversal as the metaphor for restoration from suffering; the darkest time becoming dawn inverts the Amos 5:20 judgment image (the day of the LORD: darkness not light, gloom not dawn). The restoration-as-light vocabulary will be fulfilled but through a very different path than Zophar envisions.</p>",
    "18": "<p><em>wᵉḇāṭaḥtā kî-yēš tiqwāh wᵉḥāpâartā lāḇeṭaḥ tiškaḇ</em> — &#8220;you will have confidence, because there is hope; you will look around you and rest in security.&#8221; <em>Yēš tiqwāh</em> (there is hope) — the word <em>tiqwāh</em> appears again; Zophar is offering hope to the one whom he has accused of hopelessness. The pastoral form is correct; the theological premise (you are being punished for sin) is not.</p>",
    "19": "<p><em>wᵉrāḇaṣtā wᵉʾên maḥᵃrîḏ ûḥillû pāneḵā rabbîm</em> — &#8220;you will lie down, and no one will make you afraid; many will come seeking your goodwill.&#8221; The reversal from isolation (Job has been abandoned by kinsmen and friends, 19:13-19) to being sought out is the restoration image. <em>Ḥillû pāneḵā</em> (seek your favor/caress your face) — a phrase for supplication; the restored Job will be the one to whom others come for favor and intercession, which is exactly what happens in 42:8-9 when the Friends must ask Job to pray for them.</p>",
    "20": "<p><em>wᵉʿênê rᵉšāʿîm tiklenāh wᵉmānôs ʾāḇaḏ minnêhem wᵉtiqwāṯām mappāḥ-nāpeš</em> — &#8220;but the eyes of the wicked will fail; all means of escape will be closed to them, and their only hope is to breathe their last.&#8221; The climactic contrast — Job&#8217;s restored hope versus the wicked&#8217;s hopeless <em>tiqwāh</em>. <em>Mappāḥ-nāpeš</em> (the breathing out of the soul/the gasp of the dying) — the most bitter possible content of hope: the wicked&#8217;s only hope is to exhale their last breath. The grim wordplay on <em>tiqwāh</em> as both legitimate hope (vv.18) and the mere hope of death frames the chapter&#8217;s final irony.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'job')
    merge_comm(existing, JOB)
    save_comm('mkt-original', 'job', existing)
    print('Job 8-11 mkt-original written.')

if __name__ == '__main__':
    main()
